import React, { createContext, useState, useEffect } from 'react';

export const LocationContext = createContext();

export const LocationProvider = ({ children }) => {
  const [selectedLocation, setSelectedLocation] = useState(null);
  const [isLocating, setIsLocating] = useState(false);

  // Автоматическое определение геолокации при загрузке приложения
  useEffect(() => {
    const getUserLocation = () => {
      setIsLocating(true);

      if (navigator.geolocation) {
        navigator.geolocation.getCurrentPosition(
          (position) => {
            const userLocation = {
              lat: position.coords.latitude,
              lon: position.coords.longitude,
              name: null // Имя локации не задано при автоопределении
            };

            console.log('Автоматически определена геолокация:', userLocation);
            setSelectedLocation(userLocation);
            setIsLocating(false);
          },
          (error) => {
            console.error('Ошибка при определении геолокации:', error);
            setIsLocating(false);
          },
          { 
            enableHighAccuracy: true,
            timeout: 5000,
            maximumAge: 0
          }
        );
      } else {
        console.error('Геолокация не поддерживается в этом браузере');
        setIsLocating(false);
      }
    };

    // Запускаем определение геолокации при загрузке
    getUserLocation();
  }, []);

  return (
    <LocationContext.Provider value={{ selectedLocation, setSelectedLocation, isLocating }}>
      {children}
    </LocationContext.Provider>
  );
};

export default LocationProvider;
